'use client'
import { useEffect, useRef, useState } from 'react'
import type { ThreatMapPoint } from '@/lib/otx'

interface Props { points: ThreatMapPoint[] }

interface DisplayPoint {
  srcLat: number; srcLng: number
  dstLat: number; dstLng: number
  type: string; severity: number; label: string; sourceUrl?: string
}

const TYPE_COLOR: Record<string, string> = {
  Ransomware: '#ff3a5c', APT: '#a78bfa', Phishing: '#ff8c42',
  DDoS: '#ffd700', Malware: '#ff3a5c', Scanner: '#00aaff', Threat: '#64748b',
}

function hexToRgb(hex: string): [number, number, number] {
  const r = parseInt(hex.slice(1,3),16)/255
  const g = parseInt(hex.slice(3,5),16)/255
  const b = parseInt(hex.slice(5,7),16)/255
  return [r, g, b]
}

// Convert lat/lng to 3D sphere coords
function latLngToVec3(lat: number, lng: number, radius: number): [number, number, number] {
  const phi   = (90 - lat) * (Math.PI / 180)
  const theta = (lng + 180) * (Math.PI / 180)
  return [
    -radius * Math.sin(phi) * Math.cos(theta),
     radius * Math.cos(phi),
     radius * Math.sin(phi) * Math.sin(theta),
  ]
}

export function ThreatMapPanel({ points }: Props) {
  const canvasRef  = useRef<HTMLDivElement>(null)
  const [display, setDisplay]   = useState<DisplayPoint[]>([])
  const [selected, setSelected] = useState<DisplayPoint | null>(null)
  const [count, setCount]       = useState(0)
  const [loading, setLoading]   = useState(true)
  const threeRef = useRef<any>(null)

  // Build display points client-side only (Math.random)
  useEffect(() => {
    const pts = points.map(p => ({
      srcLat: p.lat, srcLng: p.lng,
      dstLat: p.lat + (Math.random() - 0.5) * 40,
      dstLng: p.lng + (Math.random() - 0.5) * 60,
      type: p.type, severity: p.severity, label: p.label,
    }))
    setDisplay(pts)
    setCount(pts.length)
  }, [points])

  // Poll for fresh data
  useEffect(() => {
    const iv = setInterval(async () => {
      try {
        const r = await fetch('/api/v1/threat?limit=60')
        if (!r.ok) return
        const d = await r.json()
        if (!Array.isArray(d) || d.length === 0) return
        const next: DisplayPoint[] = 'srcLat' in d[0]
          ? d.map((ev: any) => ({ srcLat:ev.srcLat, srcLng:ev.srcLng, dstLat:ev.dstLat, dstLng:ev.dstLng, type:ev.type, severity:ev.severity, label:ev.details??`${ev.srcCountry}→${ev.dstCountry}`, sourceUrl:ev.sourceUrl }))
          : d.map((p: any) => ({ srcLat:p.lat, srcLng:p.lng, dstLat:p.lat+(Math.random()-0.5)*40, dstLng:p.lng+(Math.random()-0.5)*60, type:p.type, severity:p.severity, label:p.label }))
        setDisplay(next)
        setCount(next.length)
      } catch {}
    }, 60_000)
    return () => clearInterval(iv)
  }, [])

  // Three.js globe
  useEffect(() => {
    if (!canvasRef.current || display.length === 0) return

    const container = canvasRef.current
    const W = container.clientWidth
    const H = container.clientHeight || 420

    // Dynamically import Three.js
    import('three').then((THREE) => {
      // Clean up previous
      if (threeRef.current) {
        threeRef.current.renderer.dispose()
        threeRef.current.animId && cancelAnimationFrame(threeRef.current.animId)
        container.innerHTML = ''
      }

      // Scene
      const scene    = new THREE.Scene()
      const camera   = new THREE.PerspectiveCamera(45, W / H, 0.1, 1000)
      camera.position.set(0, 0, 2.8)

      const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true })
      renderer.setSize(W, H)
      renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2))
      renderer.setClearColor(0x000000, 0)
      container.appendChild(renderer.domElement)

      // Globe
      const RADIUS = 1
      const globeGeo = new THREE.SphereGeometry(RADIUS, 64, 64)

      // Earth texture using canvas (land masses as green dots pattern)
      const texCanvas = document.createElement('canvas')
      texCanvas.width = 2048; texCanvas.height = 1024
      const ctx = texCanvas.getContext('2d')!

      // Ocean
      ctx.fillStyle = '#060c1a'
      ctx.fillRect(0, 0, 2048, 1024)

      // Land using simplified country boundaries via lat/lng dots
      ctx.fillStyle = 'rgba(0,255,170,0.12)'
      const LAND_REGIONS = [
        // North America
        { x1:0.08, y1:0.1, x2:0.28, y2:0.55 },
        // South America
        { x1:0.17, y1:0.48, x2:0.32, y2:0.92 },
        // Europe
        { x1:0.43, y1:0.08, x2:0.58, y2:0.42 },
        // Africa
        { x1:0.43, y1:0.3, x2:0.60, y2:0.82 },
        // Asia
        { x1:0.55, y1:0.05, x2:0.95, y2:0.58 },
        // Australia
        { x1:0.75, y1:0.58, x2:0.92, y2:0.82 },
        // Greenland
        { x1:0.24, y1:0.02, x2:0.38, y2:0.2 },
      ]
      for (const r of LAND_REGIONS) {
        const grd = ctx.createRadialGradient(
          (r.x1+r.x2)/2*2048, (r.y1+r.y2)/2*1024, 0,
          (r.x1+r.x2)/2*2048, (r.y1+r.y2)/2*1024,
          Math.max((r.x2-r.x1)*2048,(r.y2-r.y1)*1024)*0.6
        )
        grd.addColorStop(0, 'rgba(0,255,170,0.18)')
        grd.addColorStop(1, 'rgba(0,255,170,0.0)')
        ctx.fillStyle = grd
        ctx.beginPath()
        ctx.ellipse(
          (r.x1+r.x2)/2*2048, (r.y1+r.y2)/2*1024,
          (r.x2-r.x1)*0.5*2048, (r.y2-r.y1)*0.5*1024,
          0, 0, Math.PI*2
        )
        ctx.fill()
      }

      // Grid lines
      ctx.strokeStyle = 'rgba(0,255,170,0.04)'
      ctx.lineWidth = 1
      for (let lat = -80; lat <= 80; lat += 20) {
        const y = ((90 - lat) / 180) * 1024
        ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(2048, y); ctx.stroke()
      }
      for (let lng = -180; lng <= 180; lng += 20) {
        const x = ((lng + 180) / 360) * 2048
        ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, 1024); ctx.stroke()
      }

      const texture  = new THREE.CanvasTexture(texCanvas)
      const globeMat = new THREE.MeshPhongMaterial({
        map:         texture,
        transparent: true,
        opacity:     0.95,
        shininess:   15,
        specular:    new THREE.Color(0x003311),
      })
      const globe = new THREE.Mesh(globeGeo, globeMat)
      scene.add(globe)

      // Atmosphere glow
      const atmGeo = new THREE.SphereGeometry(RADIUS * 1.05, 32, 32)
      const atmMat = new THREE.MeshPhongMaterial({
        color:       0x00ffaa,
        transparent: true,
        opacity:     0.06,
        side:        THREE.FrontSide,
      })
      scene.add(new THREE.Mesh(atmGeo, atmMat))

      // Lights
      scene.add(new THREE.AmbientLight(0x223344, 2.5))
      const sun = new THREE.DirectionalLight(0x00ffaa, 0.8)
      sun.position.set(5, 3, 5)
      scene.add(sun)
      const fill = new THREE.DirectionalLight(0x002244, 0.4)
      fill.position.set(-5, -2, -3)
      scene.add(fill)

      // Attack arcs as tube geometries
      const arcGroup = new THREE.Group()
      scene.add(arcGroup)

      function makeCurve(src: DisplayPoint): THREE.CatmullRomCurve3 {
        const [sx,sy,sz] = latLngToVec3(src.srcLat, src.srcLng, RADIUS)
        const [dx,dy,dz] = latLngToVec3(src.dstLat, src.dstLng, RADIUS)
        const mid = new THREE.Vector3((sx+dx)/2, (sy+dy)/2, (sz+dz)/2)
        mid.normalize().multiplyScalar(RADIUS * 1.45) // arc height
        return new THREE.CatmullRomCurve3([
          new THREE.Vector3(sx,sy,sz),
          mid,
          new THREE.Vector3(dx,dy,dz),
        ])
      }

      display.forEach((pt) => {
        const color  = hexToRgb(TYPE_COLOR[pt.type] ?? '#64748b')
        const curve  = makeCurve(pt)
        const geo    = new THREE.TubeGeometry(curve, 32, 0.004, 4, false)
        const mat    = new THREE.MeshBasicMaterial({
          color: new THREE.Color(...color),
          transparent: true,
          opacity: 0.5 + (pt.severity / 5) * 0.4,
        })
        arcGroup.add(new THREE.Mesh(geo, mat))

        // Source dot
        const [sx,sy,sz] = latLngToVec3(pt.srcLat, pt.srcLng, RADIUS + 0.012)
        const dotGeo = new THREE.SphereGeometry(pt.severity >= 4 ? 0.022 : 0.014, 8, 8)
        const dotMat = new THREE.MeshBasicMaterial({ color: new THREE.Color(...color) })
        const dot = new THREE.Mesh(dotGeo, dotMat)
        dot.position.set(sx, sy, sz)
        arcGroup.add(dot)
      })

      // Stars background
      const starGeo = new THREE.BufferGeometry()
      const starPos = new Float32Array(3000)
      for (let i = 0; i < 3000; i++) {
        starPos[i] = (Math.random() - 0.5) * 20
      }
      starGeo.setAttribute('position', new THREE.BufferAttribute(starPos, 3))
      const starMat = new THREE.PointsMaterial({ color:0xffffff, size:0.015, transparent:true, opacity:0.6 })
      scene.add(new THREE.Points(starGeo, starMat))

      // Mouse drag rotation
      let isDragging = false, prevX = 0, prevY = 0
      let rotX = 0.3, rotY = 0, velX = 0, velY = 0.001

      const el = renderer.domElement
      el.addEventListener('mousedown', (e) => { isDragging=true; prevX=e.clientX; prevY=e.clientY })
      el.addEventListener('touchstart', (e) => { isDragging=true; prevX=e.touches[0].clientX; prevY=e.touches[0].clientY })
      window.addEventListener('mouseup',   () => isDragging=false)
      window.addEventListener('touchend',  () => isDragging=false)
      window.addEventListener('mousemove', (e) => {
        if (!isDragging) return
        velY = (e.clientX - prevX) * 0.005
        velX = (e.clientY - prevY) * 0.003
        rotY += velY; rotX += velX
        rotX = Math.max(-1.2, Math.min(1.2, rotX))
        prevX=e.clientX; prevY=e.clientY
      })
      el.addEventListener('touchmove', (e) => {
        if (!isDragging) return
        e.preventDefault()
        const dx = e.touches[0].clientX - prevX
        const dy = e.touches[0].clientY - prevY
        velY=dx*0.005; velX=dy*0.003
        rotY+=velY; rotX+=velX
        rotX=Math.max(-1.2,Math.min(1.2,rotX))
        prevX=e.touches[0].clientX; prevY=e.touches[0].clientY
      }, { passive:false })

      // Animate
      let animId: number
      function animate() {
        animId = requestAnimationFrame(animate)
        if (!isDragging) {
          velY += (0.0015 - velY) * 0.05 // drift toward slow auto-rotate
          velX *= 0.92
          rotY += velY
          rotX += velX
          rotX = Math.max(-1.2, Math.min(1.2, rotX))
        }
        globe.rotation.y    = rotY
        globe.rotation.x    = rotX
        arcGroup.rotation.y = rotY
        arcGroup.rotation.x = rotX
        renderer.render(scene, camera)
      }
      animate()
      setLoading(false)

      // Resize handler
      const onResize = () => {
        const W2 = container.clientWidth, H2 = container.clientHeight || 420
        camera.aspect = W2/H2; camera.updateProjectionMatrix()
        renderer.setSize(W2, H2)
      }
      window.addEventListener('resize', onResize)

      threeRef.current = { renderer, animId, cleanup: () => {
        cancelAnimationFrame(animId)
        window.removeEventListener('resize', onResize)
        renderer.dispose()
      }}
    }).catch(err => {
      console.error('Three.js load error:', err)
      setLoading(false)
    })

    return () => { threeRef.current?.cleanup?.() }
  }, [display])

  return (
    <div className="glass overflow-hidden animate-fin">
      {/* Header */}
      <div className="flex items-center justify-between px-4 py-3 border-b border-white/[0.06]">
        <div className="flex items-center gap-2">
          <div className="live-dot live-dot-red"/>
          <span className="font-mono text-[11px] tracking-widest uppercase" style={{color:'#00ffaa'}}>
            Global Threat Map
          </span>
          <span className="font-mono text-[10px] text-slate-600 ml-1">— {count} OTX events</span>
        </div>
        <div className="flex items-center gap-3">
          <span className="font-mono text-[9px] text-slate-600 hidden sm:block">drag to rotate</span>
          <a href="https://otx.alienvault.com" target="_blank" rel="noreferrer"
            className="font-mono text-[9px] text-slate-600 hover:text-slate-400 transition-colors hidden sm:block">
            AlienVault OTX ↗
          </a>
        </div>
      </div>

      {/* Globe container */}
      <div className="relative" style={{height:'420px', background:'#03050a'}}>
        {loading && (
          <div className="absolute inset-0 flex items-center justify-center z-10">
            <div className="font-mono text-[12px] animate-pulse" style={{color:'#00ffaa'}}>
              ⟳ Loading 3D globe...
            </div>
          </div>
        )}
        <div ref={canvasRef} className="w-full h-full" style={{cursor:'grab'}}/>

        {/* Legend */}
        <div className="absolute bottom-3 left-3 flex gap-2 flex-wrap">
          {Object.entries(TYPE_COLOR).map(([t,c]) => (
            <div key={t} className="flex items-center gap-1">
              <div className="w-2 h-2 rounded-full" style={{background:c,boxShadow:`0 0 6px ${c}`}}/>
              <span className="font-mono text-[9px] text-slate-500 hidden sm:block">{t}</span>
            </div>
          ))}
        </div>

        {/* Stats overlay */}
        <div className="absolute top-3 left-3 flex gap-2">
          {Object.entries(
            display.reduce((acc,pt)=>{ acc[pt.type]=(acc[pt.type]??0)+1; return acc },{} as Record<string,number>)
          ).slice(0,3).map(([type,n]) => (
            <div key={type} className="font-mono text-[9px] px-2 py-1 rounded-md"
              style={{background:'rgba(0,0,0,0.6)',border:`1px solid ${TYPE_COLOR[type]??'#64748b'}40`,color:TYPE_COLOR[type]??'#64748b'}}>
              {type} {n}
            </div>
          ))}
        </div>
      </div>
    </div>
  )
}
